mapper.select:
SELECT q.*, u.username as user_name, u.avatar
FROM question q
LEFT JOIN user u ON q.user_id = u.id
WHERE q.status = 'OPEN'

    AND q.created_at >= DATE_SUB(NOW(), INTERVAL #{timeRangeDays} DAY)


    AND q.view_count >= #{minViewCount}


    AND q.answer_count >= #{minAnswerCount}


    AND q.vote_count >= #{minVoteCount}



        ORDER BY q.view_count DESC


        ORDER BY q.answer_count DESC


        ORDER BY q.vote_count DESC


        ORDER BY (q.view_count + q.answer_count * 2 + q.vote_count * 3) DESC


LIMIT #{limit}
